const c=[{id:1,name:"Identity",essence:"Investigating the sense of self",instruction:"Ask yourself: Who am I?",description:`This inquiry invites you to look directly at the sense of self.

Rather than answering intellectually, simply observe what appears when the question is asked.

Inquiry is not about finding the correct answer.

It is about noticing what reveals itself within awareness.`,color:"#3D5A80"},{id:2,name:"Letting Go",essence:"Seeing what is not essential",instruction:"Ask yourself: What am I not?",description:`This inquiry asks you to observe what you are not.

Notice the thoughts, sensations, and experiences that appear and disappear.

If something changes, can it be what you truly are?

Simply observe without conclusion.`,color:"#5B8A72"},{id:3,name:"What Remains",essence:"Looking beyond temporary experience",instruction:"Ask yourself: If this ends, what remains?",description:`This inquiry points to what is unchanging.

Imagine everything you experience ending — thoughts, sensations, perceptions.

What remains when all experience ceases?

Simply notice what is always present.`,color:"#7A6F9B"},{id:4,name:"The Observer",essence:"Exploring the source of awareness",instruction:"Ask yourself: Where is the one watching from?",description:`This inquiry investigates the sense of a location of awareness.

Look for the one who is watching your experience.

Where does awareness seem to be located?

Simply observe what is found.`,color:"#8B7355"},{id:5,name:"Separation",essence:"Questioning the boundary between self and world",instruction:"Ask yourself: Am I separate?",description:`This inquiry questions the boundary between self and experience.

Look for the line that divides you from your experience.

Is there a separation between awareness and what appears in it?

Simply notice what is revealed.`,color:"#6B8E9E"},{id:6,name:"The Doer",essence:"Observing action without a controller",instruction:"Ask yourself: Is there a doer?",description:`This inquiry looks for the one who acts.

When an action happens, who is doing it?

Can you find the doer separate from the doing?

Simply observe without trying to answer.`,color:"#3D5A80"},{id:7,name:"Thought",essence:"Seeing thoughts as appearances",instruction:"Ask yourself: What is a thought?",description:`This inquiry investigates the nature of thinking.

Notice a thought arising in awareness.

What is its substance? Where does it come from?

Simply observe thoughts without believing them.`,color:"#5B8A72"},{id:8,name:"The Constant",essence:"Discovering what remains stable",instruction:"Ask yourself: What never changes?",description:`This inquiry points to the unchanging background.

Notice everything that changes — thoughts, feelings, sensations.

What is it that never changes?

Simply rest in what remains constant.`,color:"#7A6F9B"},{id:9,name:"Awareness",essence:"Questioning ownership of awareness",instruction:"Ask yourself: Is awareness personal?",description:`This inquiry questions the ownership of awareness.

Does awareness belong to you, or do you appear in awareness?

Is there a personal quality to pure knowing?

Simply observe what is noticed.`,color:"#8B7355"},{id:10,name:"The One Within",essence:"Resting in the deepest presence",instruction:"Ask yourself: What is the one within?",description:`This inquiry looks for the innermost presence.

Look for what feels most intimately 'you'.

What is the one that knows all experience?

Simply rest in this looking.`,color:"#6B8E9E"}],l=["There are no right or wrong answers","Simply observe what appears within you","Let all thoughts and feelings be welcome","Inquiry is about noticing, not solving","Stay relaxed and open","Short sessions are enough"],p=[{label:"3 min",seconds:180},{label:"5 min",seconds:300}],h=[{question:"What is my true nature?",answer:"You are pure awareness, not the body or mind. You are the witness, not the experience.",furtherMeaning:"All experiences change, but awareness remains constant. Recognizing this is freedom."},{question:"What is the nature of the world?",answer:"It appears in awareness, like a dream. It is not separate from you.",furtherMeaning:"The world seems real but depends entirely on awareness for its existence."},{question:"What does liberation mean after being enlightened?",answer:"Nothing binds you. You were always free. Liberation is recognition, not achievement.",furtherMeaning:"Bondage was never real. It was only a misunderstanding of identity."},{question:"What is the nature of ego after being enlightened?",answer:"It dissolves. No doer remains. Actions happen without ownership.",furtherMeaning:"The sense of 'I act' disappears, leaving only spontaneous flow."},{question:"What remains after complete realization?",answer:"Only awareness - silent, infinite, complete. Nothing else truly exists.",furtherMeaning:"All distinctions dissolve, leaving only pure being."}],u=[49,50,50,50,31],o=["#3D5A80","#5B8A72","#7A6F9B","#8B7355","#6B8E9E"],d=(()=>{const s=[];let e=1;return h.forEach((n,i)=>{const a=u[i]??1,r=o[i%o.length];for(let t=0;t<a;t+=1)s.push({id:e,title:`Card ${e}`,question:n.question,answer:n.answer,furtherMeaning:n.furtherMeaning,color:r}),e+=1}),s})();export{c as a,l as b,p as d,d as i};
